#!/bin/bash
# ============================================================
# LUXARDO FASHION Fashion World — FINAL FIX SCRIPT
# Fixes: CheckoutPage, OrderConfirmation, Firestore rules
# Run in Codespace terminal:  bash FINAL-FIX.sh
# ============================================================
set -e
echo "🚀 LUXARDO FASHION Final Fix Script Starting..."
cd /workspaces/LUXARDO FASHION-website

# ---- 1. Fix CheckoutPage.tsx via base64 (no heredoc issues) ----
echo ""
echo "📝 Fixing CheckoutPage.tsx..."
python3 - << 'PYEOF'
import base64, os

b64 = ""

content = base64.b64decode(b64).decode('utf-8')
os.makedirs('src/pages', exist_ok=True)
with open('src/pages/CheckoutPage.tsx', 'w', encoding='utf-8') as f:
    f.write(content)
lines = content.count('\n')
print(f"✅ CheckoutPage.tsx written: {lines} lines, {len(content)} bytes")
PYEOF

# ---- 2. Fix OrderConfirmationPage.tsx via base64 ----
echo ""
echo "📝 Fixing OrderConfirmationPage.tsx..."
python3 - << 'PYEOF'
import base64, os

b64 = ""

content = base64.b64decode(b64).decode('utf-8')
with open('src/pages/OrderConfirmationPage.tsx', 'w', encoding='utf-8') as f:
    f.write(content)
lines = content.count('\n')
print(f"✅ OrderConfirmationPage.tsx written: {lines} lines, {len(content)} bytes")
PYEOF

# ---- 3. Patch firestore.rules to add wishlist permissions ----
echo ""
echo "🔒 Step 3: Patching Firestore rules (wishlist fix)..."
python3 - << 'PYEOF'
import re

with open('firestore.rules', 'r') as f:
    content = f.read()

# Check if wishlist rule already exists
if 'wishlists' in content:
    print("⏭️  Wishlist rules already present, skipping")
else:
    # Add wishlist rules before the closing brace of 'match /databases/{database}/documents'
    wishlist_rule = '''
    // Wishlist - users can only read/write their own wishlist
    match /wishlists/{userId} {
      allow read, write: if request.auth != null && request.auth.uid == userId;

      match /items/{itemId} {
        allow read, write: if request.auth != null && request.auth.uid == userId;
      }
    }

    // User wishlist as subcollection style
    match /users/{userId}/wishlist/{itemId} {
      allow read, write: if request.auth != null && request.auth.uid == userId;
    }
'''
    # Insert before the last closing braces
    # Find the last match /databases block and insert before its closing
    insert_pos = content.rfind('  }')  # Find the last '  }' before the final '}'
    if insert_pos > 0:
        content = content[:insert_pos] + wishlist_rule + content[insert_pos:]
        with open('firestore.rules', 'w') as f:
            f.write(content)
        print("✅ Wishlist rules added to firestore.rules")
    else:
        print("⚠️  Could not find insertion point - please check firestore.rules manually")
PYEOF

# ---- 4. Verify file sizes ----
echo ""
echo "✅ Step 4: Verifying files..."
wc -l src/pages/CheckoutPage.tsx src/pages/OrderConfirmationPage.tsx
echo ""
echo "CheckoutPage first 5 lines:"
head -5 src/pages/CheckoutPage.tsx
echo ""
echo "CheckoutPage userId line:"
grep -n "userId" src/pages/CheckoutPage.tsx | head -3

# ---- 5. Test build ----
echo ""
echo "🔨 Step 5: Testing build..."
npm run build
if [ $? -eq 0 ]; then
  echo ""
  echo "✅ BUILD SUCCESSFUL!"
else
  echo ""
  echo "❌ BUILD FAILED. Check errors above."
  exit 1
fi

# ---- 6. Commit and push ----
echo ""
echo "📤 Step 6: Committing and pushing..."
git add src/pages/CheckoutPage.tsx src/pages/OrderConfirmationPage.tsx firestore.rules
git status
git commit -m "fix: complete checkout form with userId, fix order confirmation, fix wishlist permissions"
git push
echo "✅ Pushed to GitHub"

# ---- 7. Deploy to Firebase ----
echo ""
echo "🔥 Step 7: Deploying to Firebase..."
firebase deploy --only hosting,firestore:rules,firestore:indexes
echo ""
echo "============================================================"
echo "🎉 ALL FIXES DEPLOYED!"
echo "   Website: https://LUXARDO FASHION-fashion-website.web.app"
echo ""
echo "   What was fixed:"
echo "   ✅ CheckoutPage: Full customer form + userId (Firestore rules fix)"
echo "   ✅ Order confirmation: Now shows real order details"
echo "   ✅ Wishlist: Firestore permission error fixed"
echo "   ✅ Orders will now appear in admin/dispatch panel"
echo "============================================================"
